#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=1e5+5;
int n,SUM[MAXN];
int MAXX[MAXN],MAXANS[MAXN];
struct node
{
	int s,a;
}t[MAXN];
bool cmp(node x,node y)
{
	return x.a>y.a;
}
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	scanf("%d",&n);
	for(int i=1;i<=n;++i)
	{
		scanf("%d",&t[i].s);
	}
	for(int i=1;i<=n;++i)
	{
		scanf("%d",&t[i].a);
	}
	sort(t+1,t+n+1,cmp);
	for(int i=1;i<=n;++i)
	{
		SUM[i]=SUM[i-1]+t[i].a;
		MAXX[i]=max(MAXX[i-1],t[i].s);
	}
	for(int i=n;i;--i)
	{
		MAXANS[i]=max(MAXANS[i+1],t[i].s*2+t[i].a);
	}
	for(int i=1;i<=n;++i){
		printf("%d\n",max(SUM[i]+2*MAXX[i],SUM[i-1]+MAXANS[i]));
	}
	return false;
}
